{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 tanh Distortion\par}
{\pard \ql \f0 \sa180 \li0 \fi0 Add tanh distortion to a signal. Provides a simple soft-clipping style effect with output gain control.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 Bat Ears\par}
{\pard \ql \f0 \sa180 \li0 \fi0 Heterodyning bat ears effect with strict Nyquist and audible monitor modes. Designed for carrier-frequency ring modulation and ultrasonic monitoring.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 12-channel Trim\par}
{\pard \ql \f0 \sa180 \li0 \fi0 Individual trimming controls for 12 channels. Useful for automated gain control in a parent channel.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 10 to 2-channel mixer\par}
{\pard \ql \f0 \sa180 \li0 \fi0 Individual level and pan controls for 10 channels.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 MSConvert\par}
{\pard \ql \f0 \sa180 \li0 \fi0 Convert a stereo signal either from Mid-Side to AB-format or vice versa. Attenuation is evenly distributed at -3 dB in both directions so that a unity-gain round trip preserves the signal.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 Phase Invert\par}
{\pard \ql \f0 \sa180 \li0 \fi0 Invert the phase of the right channel.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 Rotate\par}
{\pard \ql \f0 \sa180 \li0 \fi0 Alter stereo spatiality with equal-power rotation. Useful for rotating an ambisonic B-format sound field or widening stereo material.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 RotMS\par}
{\pard \ql \f0 \sa180 \li0 \fi0 Adjust stereo spatiality with MS/AB rotation, panning, and gain control. Supports conversion between AB and MS workflows with equal-power gain handling.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 Stereo2Mono\par}
{\pard \ql \f0 \sa180 \li0 \fi0 Convert stereo to dual-mono with selectable -6 dB or -3 dB attenuation. Useful when you need a centered mono sum without losing level control.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 Stereo Utility\par}
{\pard \ql \f0 \sa180 \li0 \fi0 Utility processor similar to Ableton Utility.\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Gain\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Phase invert per channel\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Global mute/unmute\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Width (0% to 400%)\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Bass mono (50 Hz to 500 Hz)\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Balance\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab DC offset removal All automatable controls are smoothed per sample.\sa180\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
{\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
\widowctrl\hyphauto

